import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/launch-targets.DIrU2w_6.js";const s=JSON.parse(`{"title":"Avviare il Gioco in VS Code","description":"Impara come avviare un'istanza di Minecraft da Visual Studio Code.","frontmatter":{"title":"Avviare il Gioco in VS Code","description":"Impara come avviare un'istanza di Minecraft da Visual Studio Code.","authors":["dicedpixels"],"prev":{"text":"Aprire un progetto in VS Code","link":"./opening-a-project"},"next":{"text":"Generare le Sorgenti in VS Code","link":"./generating-sources"},"files":[]},"headers":[],"relativePath":"it_it/develop/getting-started/vscode/launching-the-game.md","filePath":"translated/it_it/develop/getting-started/vscode/launching-the-game.md","lastUpdated":1770561656000}`);var c={name:`it_it/develop/getting-started/vscode/launching-the-game.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Avviare il Gioco in VS Code <a class="header-anchor" href="#h1" aria-label="Permalink to “Avviare il Gioco in VS Code”">​</a></h1><p>La toolchain di Fabric si integra con Visual Studio Code per fornire un modo comodo di eseguire un&#39;istanza del gioco su cui effettuare test e debugging della tua mod.</p><h2 id="generating-launch-targets" tabindex="-1">Generare gli obiettivi di avvio <a class="header-anchor" href="#generating-launch-targets" aria-label="Permalink to “Generare gli obiettivi di avvio”">​</a></h2><p>Per eseguire il gioco attivando il debugging, dovrai generare gli obiettivi di avvio eseguendo l&#39;attività Gradle <code>vscode</code>.</p><p>Questo si può fare dalla vista Gradle all&#39;interno di Visual Studio Code: aprila e naviga all&#39;attività <code>vscode</code> in <strong>Tasks</strong> &gt; <strong><code>ide</code></strong>. Cliccaci due volte o usa il pulsante <strong>Run Task</strong> per eseguire l&#39;attività.</p><p><img src="/assets/develop/getting-started/vscode/gradle-vscode.png" alt="Attività vscode nella vista Gradle" loading="lazy"></p><p>In alternativa si può usare direttamente il terminale: aprine uno da <strong>Terminal</strong> &gt; <strong>New Terminal</strong> ed esegui:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./gradlew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vscode</span></span></code></pre></div><p><img src="/assets/develop/getting-started/vscode/terminal-vscode.png" alt="Attività vscode nel terminale" loading="lazy"></p><h3 id="using-launch-targets" tabindex="-1">Usare gli obiettivi di avvio <a class="header-anchor" href="#using-launch-targets" aria-label="Permalink to “Usare gli obiettivi di avvio”">​</a></h3><p>Una volta generati, puoi usare gli obiettivi di avvio aprendo la vista <strong>Run and Debug</strong>, selezionando l&#39;obiettivo desiderato e premendo il pulsante <strong>Start Debugging</strong> (<kbd>F5</kbd>).</p><p><img src="/assets/develop/getting-started/vscode/launch-targets.png" alt="Obiettivi di avvio" loading="lazy"></p>`,12)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};